47: /*
48:  * curlx_base64_decode()
49:  *
50:  * Given a base64 null-terminated string at src, decode it and return a
51:  * pointer in *outptr to a newly allocated memory area holding decoded data.
52:  * Size of decoded data is returned in variable pointed by outlen.
53:  *
54:  * Returns CURLE_OK on success, otherwise specific error code. Function
55:  * output shall not be considered valid unless CURLE_OK is returned.
56:  *
57:  * When decoded data length is 0, returns NULL in *outptr.
58:  *
59:  * @unittest: 1302
60:  */
61: CURLcode curlx_base64_decode(const char *src,
62:                              uint8_t **outptr, size_t *outlen)
63: {
64:   size_t srclen = 0;
65:   size_t padding = 0;
66:   size_t i;
67:   size_t numQuantums;
68:   size_t fullQuantums;
69:   size_t rawlen = 0;
70:   unsigned char *pos;
71:   unsigned char *newstr;
72:   unsigned char lookup[256];
73: 
74:   *outptr = NULL;
75:   *outlen = 0;
76:   srclen = strlen(src);
77: 
78:   /* Check the length of the input string is valid */
79:   if(!srclen || srclen % 4)
80:     return CURLE_BAD_CONTENT_ENCODING;
81: 
82:   /* srclen is at least 4 here */
83:   while(src[srclen - 1 - padding] == '=') {
84:     /* count padding characters */
85:     padding++;
86:     /* A maximum of two = padding characters is allowed */
87:     if(padding > 2)
88:       return CURLE_BAD_CONTENT_ENCODING;
89:   }
90: 
91:   /* Calculate the number of quantums */
92:   numQuantums = srclen / 4;
93:   fullQuantums = numQuantums - (padding ? 1 : 0);
94: 
95:   /* Calculate the size of the decoded string */
96:   rawlen = (numQuantums * 3) - padding;
97: 
98:   /* Allocate our buffer including room for a null-terminator */
99:   newstr = curlx_malloc(rawlen + 1);
100:   if(!newstr)
101:     return CURLE_OUT_OF_MEMORY;
102: 
103:   pos = newstr;
104: 
105:   memset(lookup, 0xff, sizeof(lookup));
106:   memcpy(&lookup['+'], decodetable, sizeof(decodetable));
107: 
108:   /* Decode the complete quantums first */
109:   for(i = 0; i < fullQuantums; i++) {
110:     unsigned char val;
111:     unsigned int x = 0;
112:     int j;
113: 
114:     for(j = 0; j < 4; j++) {
115:       val = lookup[(unsigned char)*src++];
116:       if(val == 0xff) /* bad symbol */
117:         goto bad;
118:       x = (x << 6) | val;
119:     }
120:     pos[2] = x & 0xff;
121:     pos[1] = (x >> 8) & 0xff;
122:     pos[0] = (x >> 16) & 0xff;
123:     pos += 3;
124:   }
125:   if(padding) {
126:     /* this means either 8 or 16 bits output */
127:     unsigned char val;
128:     unsigned int x = 0;
129:     int j;
130:     size_t padc = 0;
131:     for(j = 0; j < 4; j++) {
132:       if(*src == '=') {
133:         x <<= 6;
134:         src++;
135:         if(++padc > padding)
136:           /* this is a badly placed '=' symbol! */
137:           goto bad;
138:       }
139:       else {
140:         val = lookup[(unsigned char)*src++];
141:         if(val == 0xff) /* bad symbol */
142:           goto bad;
143:         x = (x << 6) | val;
144:       }
145:     }
146:     if(padding == 1)
147:       pos[1] = (x >> 8) & 0xff;
148:     pos[0] = (x >> 16) & 0xff;
149:     pos += 3 - padding;
150:   }
