165: static CURLcode base64_encode(const char *table64,
166:                               uint8_t padbyte,
167:                               const uint8_t *inputbuff, size_t insize,
168:                               char **outptr, size_t *outlen)
169: {
170:   char *output;
171:   char *base64data;
172:   const unsigned char *in = (const unsigned char *)inputbuff;
173: 
174:   *outptr = NULL;
175:   *outlen = 0;
176: 
177:   if(!insize)
178:     return CURLE_OK;
179: 
180:   /* safety precaution */
181:   DEBUGASSERT(insize <= CURL_MAX_BASE64_INPUT);
182:   if(insize > CURL_MAX_BASE64_INPUT)
183:     return CURLE_TOO_LARGE;
184: 
185:   base64data = output = curlx_malloc((insize + 2) / 3 * 4 + 1);
186:   if(!output)
187:     return CURLE_OUT_OF_MEMORY;
188: 
189:   while(insize >= 3) {
190:     *output++ = table64[in[0] >> 2];
191:     *output++ = table64[((in[0] & 0x03) << 4) | (in[1] >> 4)];
192:     *output++ = table64[((in[1] & 0x0F) << 2) | ((in[2] & 0xC0) >> 6)];
193:     *output++ = table64[in[2] & 0x3F];
194:     insize -= 3;
195:     in += 3;
196:   }
197:   if(insize) {
198:     /* this is only one or two bytes now */
199:     *output++ = table64[in[0] >> 2];
200:     if(insize == 1) {
201:       *output++ = table64[((in[0] & 0x03) << 4)];
202:       if(padbyte) {
203:         *output++ = padbyte;
204:         *output++ = padbyte;
205:       }
206:     }
207:     else {
208:       /* insize == 2 */
209:       *output++ = table64[((in[0] & 0x03) << 4) | ((in[1] & 0xF0) >> 4)];
210:       *output++ = table64[((in[1] & 0x0F) << 2)];
211:       if(padbyte)
212:         *output++ = padbyte;
213:     }
214:   }
215: 
216:   /* Zero terminate */
217:   *output = '\0';
218: 
219:   /* Return the pointer to the new data (allocated memory) */
220:   *outptr = base64data;
221: 
222:   /* Return the length of the new data */
223:   *outlen = (size_t)(output - base64data);
224: 
225:   return CURLE_OK;
226: }
